@using sv_3252285e2d154a8c9fc458c386104a83.Services
@inject ISettingsService SettingsService

<div class="settings-section security-section">
    <h2>Security Settings</h2>

    @if (_loading)
    {
        <p>Loading security settings...</p>
    }
    else
    {
        <!-- Change Password Panel -->
        <div class="expandable-panel">
            <button class="panel-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <span>Change Password</span>
                <span class="expand-icon">@(_passwordPanelOpen ? "▼" : "▶")</span>
            </button>

            @if (_passwordPanelOpen)
            {
                <div class="panel-content">
                    <div class="form-group">
                        <label for="currentPassword">Current Password</label>
                        <input id="currentPassword" type="password" @bind="_currentPassword" class="form-control" />
                    </div>
                    <div class="form-group">
                        <label for="newPassword">New Password</label>
                        <input id="newPassword" type="password" @bind="_newPassword" class="form-control" />
                    </div>
                    <div class="form-group">
                        <label for="confirmPassword">Confirm Password</label>
                        <input id="confirmPassword" type="password" @bind="_confirmPassword" class="form-control" />
                    </div>
                    <button class="btn btn-primary" @onclick="UpdatePassword">Update Password</button>

                    @if (!string.IsNullOrEmpty(_passwordMessage))
                    {
                        <div class="toast-message @(_passwordError ? "toast-error" : "toast-success")">
                            @_passwordMessage
                        </div>
                    }
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="twofa-section">
            <h3>Two-Factor Authentication</h3>
            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" checked="@_twoFactorEnabled" disabled />
                    <span>Two-Factor Authentication</span>
                    <span class="status-indicator @(_twoFactorEnabled ? "status-enabled" : "status-disabled")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </label>
            </div>
            @if (_lastPasswordChange.HasValue)
            {
                <p class="info-text">Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
            }
        </div>

        <!-- Active Sessions -->
        <div class="sessions-section">
            <h3>Active Sessions</h3>
            <table class="sessions-table">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th>Action</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (session.Id != _currentSessionId)
                                {
                                    <button class="btn btn-danger btn-sm" @onclick="() => ConfirmRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="current-session-badge">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        <!-- Revoke Confirmation Dialog -->
        @if (_sessionToRevoke is not null)
        {
            <div class="dialog-overlay">
                <div class="dialog">
                    <h4>Revoke Session</h4>
                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                    <div class="dialog-actions">
                        <button class="btn btn-danger" @onclick="RevokeSession">Yes, Revoke</button>
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    </div>
                </div>
            </div>
        }
    }
</div>

@code {
    private bool _loading = true;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string _passwordMessage = "";
    private bool _passwordError;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();
    private ActiveSession? _sessionToRevoke;

    // First session is treated as the current session
    private string _currentSessionId = "session-1";

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions.ToList();
        _loading = false;
    }

    private async Task UpdatePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordMessage = "Please fill in all password fields.";
            _passwordError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordMessage = "New password and confirmation do not match.";
            _passwordError = true;
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _passwordMessage = "Password updated successfully!";
        _passwordError = false;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _lastPasswordChange = DateTime.UtcNow;
    }

    private void ConfirmRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task RevokeSession()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
    }

    private string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} minutes ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} hours ago";
        return $"{(int)diff.TotalDays} days ago";
    }
}

