    <h2>Appearance Settings</h2>

    @if (_loading)
    {
        <p>Loading appearance settings...</p>
    }
    else
    {
        <div class="appearance-form">
            <!-- Theme Selector -->
            <div class="form-group">
                <label><strong>Theme</strong></label>
                <div class="radio-group">
                    @foreach (var theme in _themes)
                    {
                        <label class="radio-label">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_selectedTheme == theme)"
                                   @onchange="() => _selectedTheme = theme" />
                            <span>@theme</span>
                        </label>
                    }
                </div>
            </div>

            <!-- Font Size Selector -->
            <div class="form-group">
                <label><strong>Font Size</strong></label>
                <div class="radio-group">
                    @foreach (var size in _fontSizes)
                    {
                        <label class="radio-label">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_selectedFontSize == size)"
                                   @onchange="() => _selectedFontSize = size" />
                            <span>@size</span>
                        </label>
                    }
                </div>
            </div>

            <!-- Language Dropdown -->
            <div class="form-group">
                <label for="language"><strong>Language</strong></label>
                <select id="language" @bind="_selectedLanguage" class="form-control">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <!-- Compact Mode Toggle -->
            <div class="form-group">
                <label class="toggle-label">
                    <input type="checkbox" @bind="_compactMode" />
                    <span><strong>Compact Mode</strong></span>
                </label>
            </div>

            <!-- Live Preview -->
            <div class="live-preview @GetPreviewClasses()">
                <h4>Live Preview</h4>
                <p class="preview-text">This is how your content will look with the selected settings.</p>
                <div class="preview-card">
                    <span class="preview-badge">Sample Card</span>
                    <p>Dashboard content appears in this style.</p>
                </div>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
            </div>

            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="toast-message toast-success">@_message</div>
            }
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private string _selectedTheme = "Light";
    private string _selectedFontSize = "Medium";
    private string _selectedLanguage = "English";
    private bool _compactMode;
    private string _message = "";

    private static readonly string[] _themes = { "Light", "Dark", "System" };
    private static readonly string[] _fontSizes = { "Small", "Medium", "Large" };
    private static readonly string[] _languages = { "English", "Spanish", "French", "German", "Japanese", "Chinese" };

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _selectedTheme = settings.Theme;
        _selectedFontSize = settings.FontSize;
        _selectedLanguage = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewClasses()
    {
        var classes = $"preview-theme-{_selectedTheme.ToLower()} preview-font-{_selectedFontSize.ToLower()}";
        if (_compactMode) classes += " preview-compact";
        return classes;
    }

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_selectedTheme, _selectedFontSize, _selectedLanguage, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _message = "Appearance settings saved!";
    }
}

