arguments.file_text:
@page "/settings"
@using sv_3252285e2d154a8c9fc458c386104a83.Components.Pages.Settings
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionSelected="SetActiveSection" />

    <main class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </main>
</div>

@code {
    private string _activeSection = "Profile";

    private void SetActiveSection(string section)
    {
        _activeSection = section;
    }
}

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 4rem);
    gap: 0;
}

/* Sidebar */
.settings-sidebar {
    width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1rem 0;
    flex-shrink: 0;
}

.settings-sidebar ul {
    list-style: none;
    padding: 0;
    margin: 0;
}

.settings-sidebar li {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    cursor: pointer;
    transition: background 0.2s, border-left 0.2s;
    border-left: 3px solid transparent;
    font-weight: 500;
}

.settings-sidebar li:hover {
    background: #e9ecef;
}

.settings-sidebar li.active {
    background: #e7f1ff;
    border-left-color: #0d6efd;
    color: #0d6efd;
}

/* Main Content */
.settings-content {
    flex: 1;
    padding: 2rem;
    max-width: 800px;
}

.settings-section h2 {
    margin-top: 0;
    margin-bottom: 1.5rem;
    font-size: 1.5rem;
    color: #212529;
}

/* Form Controls */
.form-group {
    margin-bottom: 1.25rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.4rem;
    font-weight: 500;
    color: #495057;
}

.form-control {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 0.375rem;
    font-size: 1rem;
    transition: border-color 0.15s;
    box-sizing: border-box;
}

.form-control:focus {
    border-color: #86b7fe;
    outline: 0;
    box-shadow: 0 0 0 0.2rem rgba(13, 110, 253, 0.25);
}

/* Buttons */
.btn {
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 0.375rem;
    font-size: 0.9rem;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.2s;
}

.btn-primary {
    background: #0d6efd;
    color: white;
}

.btn-primary:hover {
    background: #0b5ed7;
}

.btn-secondary {
    background: #6c757d;
    color: white;
}

.btn-secondary:hover {
    background: #5c636a;
}

.btn-danger {
    background: #dc3545;
    color: white;
}

.btn-danger:hover {
    background: #bb2d3b;
}

.btn-sm {
    padding: 0.25rem 0.5rem;
    font-size: 0.8rem;
}

.form-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

/* Toast Messages */
.toast-message {
    margin-top: 1rem;
    padding: 0.75rem 1rem;
    border-radius: 0.375rem;
    font-weight: 500;
}

.toast-success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

.toast-error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

/* Profile Section */
.avatar-preview {
    margin-bottom: 1.5rem;
    text-align: center;
}

.avatar-image {
    width: 100px;
    height: 100px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
}

.avatar-url-label {
    margin-top: 0.5rem;
    font-size: 0.85rem;
    color: #6c757d;
    word-break: break-all;
}

/* Toggle Controls */
.toggle-group {
    margin-bottom: 0.75rem;
}

.toggle-label {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    cursor: pointer;
    font-size: 0.95rem;
}

.toggle-label input[type="checkbox"] {
    width: 1.1rem;
    height: 1.1rem;
    cursor: pointer;
}

/* Radio Groups */
.radio-group {
    display: flex;
    gap: 1.5rem;
    margin-top: 0.4rem;
}

.radio-label {
    display: inline-flex;
    align-items: center;
    gap: 0.4rem;
    cursor: pointer;
}

/* Muted Channels */
.muted-channels {
    margin-top: 2rem;
    padding-top: 1.5rem;
    border-top: 1px solid #dee2e6;
}

.muted-channels h3 {
    margin-bottom: 1rem;
    font-size: 1.1rem;
}

.channel-item {
    margin-bottom: 0.5rem;
}

/* Expandable Panel */
.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    margin-bottom: 1.5rem;
}

.panel-header {
    width: 100%;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border: none;
    cursor: pointer;
    font-size: 1rem;
    font-weight: 500;
    border-radius: 0.375rem;
}

.panel-header:hover {
    background: #e9ecef;
}

.panel-content {
    padding: 1rem;
    border-top: 1px solid #dee2e6;
}

/* Two-Factor Section */
.twofa-section {
    margin-bottom: 1.5rem;
}

.twofa-section h3 {
    margin-bottom: 0.75rem;
    font-size: 1.1rem;
}

.status-indicator {
    font-size: 0.8rem;
    padding: 0.2rem 0.5rem;
    border-radius: 1rem;
    margin-left: 0.5rem;
}

.status-enabled {
    background: #d1e7dd;
    color: #0f5132;
}

.status-disabled {
    background: #f8d7da;
    color: #842029;
}

.info-text {
    font-size: 0.85rem;
    color: #6c757d;
    margin-top: 0.5rem;
}

/* Sessions Table */
.sessions-section h3 {
    margin-bottom: 0.75rem;
    font-size: 1.1rem;
}

.sessions-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 0.5rem;
}

.sessions-table th,
.sessions-table td {
    padding: 0.6rem 0.75rem;
    text-align: left;
    border-bottom: 1px solid #dee2e6;
}

.sessions-table th {
    background: #f8f9fa;
    font-weight: 600;
    font-size: 0.85rem;
    text-transform: uppercase;
    color: #6c757d;
}

.current-session-badge {
    font-size: 0.8rem;
    padding: 0.2rem 0.5rem;
    background: #cff4fc;
    color: #055160;
    border-radius: 0.25rem;
}

/* Confirmation Dialog */
.dialog-overlay {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
}

.dialog {
    background: white;
    border-radius: 0.5rem;
    padding: 1.5rem;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 10px 25px rgba(0, 0, 0, 0.2);
}

.dialog h4 {
    margin-top: 0;
    margin-bottom: 0.75rem;
}

.dialog-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.25rem;
    justify-content: flex-end;
}

/* Appearance Preview */
.live-preview {
    margin-top: 1.5rem;
    padding: 1.5rem;
    border: 2px dashed #dee2e6;
    border-radius: 0.5rem;
    transition: all 0.3s;
}

.live-preview h4 {
    margin-top: 0;
    margin-bottom: 0.75rem;
}

.preview-card {
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 0.375rem;
    margin-top: 0.75rem;
}

.preview-badge {
    display: inline-block;
    padding: 0.2rem 0.6rem;
    background: #0d6efd;
    color: white;
    border-radius: 0.25rem;
    font-size: 0.8rem;
    margin-bottom: 0.5rem;
}

/* Theme previews */
.preview-theme-dark {
    background: #1a1a2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-theme-dark .preview-card {
    background: #2d2d44;
}

.preview-theme-light {
    background: #ffffff;
    color: #212529;
}

.preview-theme-system {
    background: #f0f0f0;
    color: #333;
}

/* Font size previews */
.preview-font-small {
    font-size: 0.8rem;
}

.preview-font-medium {
    font-size: 1rem;
}

.preview-font-large {
    font-size: 1.2rem;
}

/* Compact mode preview */
.preview-compact {
    padding: 0.75rem;
}

.preview-compact .preview-card {
    padding: 0.5rem;
    margin-top: 0.4rem;
}

