+    margin-bottom: 0.75rem;
+}
+
+.dialog-actions {
+    display: flex;
+    gap: 0.75rem;
+    margin-top: 1.25rem;
+    justify-content: flex-end;
+}
+
+/* Appearance Preview */
+.live-preview {
+    margin-top: 1.5rem;
+    padding: 1.5rem;
+    border: 2px dashed #dee2e6;
+    border-radius: 0.5rem;
+    transition: all 0.3s;
+}
+
+.live-preview h4 {
+    margin-top: 0;
+    margin-bottom: 0.75rem;
+}
+
+.preview-card {
+    padding: 1rem;
+    background: #f8f9fa;
+    border-radius: 0.375rem;
+    margin-top: 0.75rem;
+}
+
+.preview-badge {
+    display: inline-block;
+    padding: 0.2rem 0.6rem;
+    background: #0d6efd;
+    color: white;
+    border-radius: 0.25rem;
+    font-size: 0.8rem;
+    margin-bottom: 0.5rem;
+}
+
+/* Theme previews */
+.preview-theme-dark {
+    background: #1a1a2e;
+    color: #e0e0e0;
+    border-color: #444;
+}
+
+.preview-theme-dark .preview-card {
+    background: #2d2d44;
+}
+
+.preview-theme-light {
+    background: #ffffff;
+    color: #212529;
+}
+
+.preview-theme-system {
+    background: #f0f0f0;
+    color: #333;
+}
+
+/* Font size previews */
+.preview-font-small {
+    font-size: 0.8rem;
+}
+
+.preview-font-medium {
+    font-size: 1rem;
+}
+
+.preview-font-large {
+    font-size: 1.2rem;
+}
+
+/* Compact mode preview */
+.preview-compact {
+    padding: 0.75rem;
+}
+
+.preview-compact .preview-card {
+    padding: 0.5rem;
+    margin-top: 0.4rem;
+}
